const item = $input.first()?.json || {};
const prompt = item.prompt || item.text || '';

return [{
  json: {
    prompt: prompt,
    text: prompt,
    type: 'keywords'
  }
}];

const response = $input.first()?.json || {};
const data = response?.data || {};
const background = data.background || '';
const roles = data.roles || {};

const items = [];

if (background) {
  items.push({json: {type: 'background', prompt: background, workflow_type: 'background', width: 1920, height: 1080}});
}

for (const [name, action] of Object.entries(roles)) {
  items.push({json: {type: 'character', character_name: name, prompt: action, workflow_type: 'person', width: 1024, height: 1024}});
}

if (items.length === 0) {
  items.push({json: {type: 'empty', prompt: '', workflow_type: 'none'}});
}

return items;

const item = $input.first()?.json || {};
const prompt = item.prompt || '';
const workflowType = item.workflow_type || 'scene';
const width = item.width || 1024;
const height = item.height || 1024;
const characterName = item.character_name || null;

return [{
  json: {
    prompt: prompt,
    optimized_prompt: prompt,
    width: width,
    height: height,
    count: 1,
    workflow_type: workflowType,
    character_name: characterName
  }
}];

const response = $input.first()?.json || {};
const originalItem = $('Split Tasks').first()?.json || {};

return [{
  json: {
    type: originalItem.type,
    character_name: originalItem.character_name,
    prompt: originalItem.prompt,
    executionId: response.prompt_id || response.id,
    workflowType: originalItem.workflow_type,
    status: 'submitted'
  }
}];

const items = $input.all();

return [{
  json: {
    success: true,
    totalTasks: items.length,
    tasks: items.map(item => ({
      type: item.json.type,
      character_name: item.json.character_name,
      executionId: item.json.executionId,
      workflowType: item.json.workflowType,
      status: item.json.status
    }))
  }
}];
